"""
Seeds all assessment templates.
Safe to re-run — uses get_or_create / update_or_create.

Templates seeded:
  1. Essential Eight (ACSC) — ML1/ML2/ML3 per control with full assessor guidance
  2. AESCSF v1 — original 5 maturity levels, 10 domains
  3. AESCSF 2023 (v2) — updated 2023 SOCI-aligned version
  4. NIST Cybersecurity Framework 2.0 — 6 functions, 22 categories
  5. ISO/IEC 27001:2022 — 4 themes, 93 controls
  6. Australian Government ISM — key security controls
  7. CIS Controls v8 — 18 controls
  8. Generic Gap Analysis
"""
from django.core.management.base import BaseCommand
from assessments.models import AssessmentTemplate, AssessmentSection, AssessmentQuestion


# ─── Helper ──────────────────────────────────────────────────────────────────
def seed_template(framework, name, description, sections_data):
    """
    sections_data: list of {name, description, questions: [...]}
    Each question tuple: (order, text, guidance, question_type, maturity_level, options, weight)
    """
    template, _ = AssessmentTemplate.objects.get_or_create(
        framework=framework, name=name,
        defaults={'description': description},
    )
    template.description = description
    template.is_active = True
    template.save()

    current_section_names = {sec['name'] for sec in sections_data}

    # Remove any sections that no longer exist in the definition (e.g. renamed sections).
    template.sections.exclude(name__in=current_section_names).delete()

    for si, sec in enumerate(sections_data):
        section, _ = AssessmentSection.objects.get_or_create(
            template=template, name=sec['name'],
            defaults={'description': sec.get('description', ''), 'order': si},
        )
        section.description = sec.get('description', '')
        section.order = si
        section.save()

        current_question_orders = [q[0] for q in sec['questions']]

        # Remove questions that no longer exist in the definition (e.g. removed controls).
        section.questions.exclude(order__in=current_question_orders).delete()

        for qi, q in enumerate(sec['questions']):
            order      = q[0]
            text       = q[1]
            guidance   = q[2]
            qtype      = q[3] if len(q) > 3 else 'YESNO'
            ml         = q[4] if len(q) > 4 else None
            options    = q[5] if len(q) > 5 else []
            weight     = q[6] if len(q) > 6 else 1.0

            AssessmentQuestion.objects.update_or_create(
                section=section, order=order,
                defaults=dict(
                    text=text, guidance=guidance,
                    question_type=qtype, maturity_level=ml,
                    options=options, weight=weight, is_required=True,
                ),
            )
    return template


