class Command(BaseCommand):
    help = 'Seed assessment templates with comprehensive guidance'

    def handle(self, *args, **options):
        self.stdout.write('Seeding assessment templates...')

        # Deactivate any stale E8 templates that aren't the canonical one (e.g. old 51-question version).
        # We can't delete them if live assessments reference them, so we hide them from the dropdown instead.
        stale = AssessmentTemplate.objects.filter(
            framework='ESSENTIAL_EIGHT'
        ).exclude(name='Essential Eight (ACSC)')
        if stale.exists():
            names = list(stale.values_list('name', flat=True))
            stale.update(is_active=False)
            self.stdout.write(self.style.WARNING(f'  Deactivated stale E8 template(s): {names}'))

        seed_template(
            'ESSENTIAL_EIGHT',
            'Essential Eight (ACSC)',
            'The Australian Cyber Security Centre Essential Eight controls with full ML1/ML2/ML3 assessor guidance, evidence sources, and specific technical indicators.',
            E8_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ Essential Eight'))

        seed_template(
            'AESCSF_V1',
            'AESCSF v1',
            'Original Australian Energy Sector Cyber Security Framework with 10 focus areas and 5 maturity levels.',
            AESCSF_V1_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ AESCSF v1'))

        seed_template(
            'AESCSF',
            'AESCSF 2023 (v2)',
            'Full AESCSF v2 framework assessment covering all 11 domains with 354 practices (MIL-1 through MIL-3, Security Profiles SP-1 through SP-3). Source: V2 AESCSF Toolkit.',
            AESCSF_V2_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ AESCSF 2023 (v2)'))

        seed_template(
            'NIST_CSF',
            'NIST Cybersecurity Framework 2.0',
            'NIST CSF 2.0 with 6 functions (Govern, Identify, Protect, Detect, Respond, Recover) and 22 categories. Choice-based maturity assessment.',
            NIST_CSF_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ NIST CSF 2.0'))

        seed_template(
            'ISO_27001',
            'ISO/IEC 27001:2022',
            'ISO/IEC 27001:2022 Annex A controls across 4 themes: Organisational, People, Physical, and Technological. Compliance-based assessment.',
            ISO_27001_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ ISO 27001:2022'))

        seed_template(
            'ISM',
            'Australian Government ISM',
            'Australian Government Information Security Manual key controls covering governance, personnel, access control, system hardening, network security, and incident response.',
            ISM_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ Australian ISM'))

        seed_template(
            'GAP_ANALYSIS',
            'Generic Gap Analysis',
            'General cybersecurity gap analysis covering governance, assets, access control, vulnerability management, incident response, data protection, and business continuity.',
            GAP_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ Generic Gap Analysis'))

        seed_template(
            'CIS',
            'CIS Controls v8',
            'Center for Internet Security Controls v8 — key controls from the 18 CIS Controls focused on enterprise security fundamentals.',
            CIS_SECTIONS,
        )
        self.stdout.write(self.style.SUCCESS('✓ CIS Controls v8'))

        self.stdout.write(self.style.SUCCESS('\nAll templates seeded successfully.'))
        self.stdout.write('Run: python manage.py seed_assessment_templates')
